import { useState } from 'react';
import { useLocalStorage } from '../hooks/useLocalStorage';
import { useLang } from '../context/LangContext';
import './Music.css';

export default function Music() {
  const { t } = useLang();
  const [note, setNote] = useLocalStorage('wedding-music-note', '');
  const [saved, setSaved] = useState(false);

  const handleSave = () => {
    setSaved(true);
    setTimeout(() => setSaved(false), 2000);
  };

  return (
    <div>
      <h2 className="section-title">
        {t.ourSongEm
          ? <>{t.ourSong} <em>{t.ourSongEm}</em></>
          : <em>{t.ourSong}</em>}
      </h2>
      <p className="section-subtitle">{t.soundtrack}</p>

      <div className="music-hero card">
        <div className="music-hero-left">
          <div className="music-icon">♪</div>
          <div>
            <div className="music-song-title">{t.songTitle}</div>
            <div className="music-artist">{t.artist}</div>
            <div className="music-album">{t.album}</div>
          </div>
        </div>
        <a
          className="yt-btn"
          href="https://www.youtube.com/results?search_query=Love+Story+Taylor+Swift+Taylor%27s+Version"
          target="_blank"
          rel="noopener noreferrer"
        >
          ▶ YouTube
        </a>
      </div>

      <div className="spotify-wrap">
        <iframe
          title="Love Story – Spotify"
          src="https://open.spotify.com/embed/track/1vrd6UOGamcKNGnSHJQlSt?utm_source=generator&theme=0"
          width="100%"
          height="152"
          frameBorder="0"
          allow="autoplay; clipboard-write; encrypted-media; fullscreen; picture-in-picture"
          loading="lazy"
        />
      </div>

      <div className="quote-block" style={{ marginTop: '1.75rem' }}>
        <p>{t.musicQuote}</p>
        <span>{t.musicQuoteAttr}</span>
      </div>

      <div className="card music-note-card">
        <div className="note-header">
          <span className="note-label">{t.noteLabel}</span>
          <span className="note-hint">{t.noteSavedHint}</span>
        </div>
        <textarea
          className="note-textarea"
          rows={4}
          placeholder={t.notePlaceholder}
          value={note}
          onChange={e => setNote(e.target.value)}
        />
        <button className="btn-primary" onClick={handleSave}>
          {saved ? t.saved : t.saveNote}
        </button>
      </div>
    </div>
  );
}
